 471→+    const peakX = x + w / 2;
 472→+    const peakY = baseY - h;
 473→+    ctx.beginPath();
 474→+    ctx.moveTo(Math.floor(peakX - w * 0.1), Math.floor(peakY + h * 0.18));
 475→+    ctx.lineTo(Math.floor(peakX), Math.floor(peakY));
