1153→+const NOTE_FREQ = {
1154→+  'C3': 130.81, 'D3': 146.83, 'G2': 98.00, 'A2': 110.00,
1155→+  'C4': 261.63, 'D4': 293.66, 'E4': 329.63, 'G4': 392.00,
1156→+  'A4': 440.00, 'C5': 523.25, 'REST': 0
1157→+};
1158→+
1159→+const melody = [
1160→+  { note: 'E4', dur: 1 }, { note: 'G4', dur: 1 }, { note: 'A4', dur: 1 }, { note: 'G4', dur: 1 },
1161→+  { note: 'E4', dur: 1 }, { note: 'D4', dur: 1 }, { note: 'C4', dur: 1 }, { note: 'REST', dur: 1 },
1162→+  { note: 'E4', dur: 1 }, { note: 'G4', dur: 1 }, { note: 'A4', dur: 1 }, { note: 'C5', dur: 1 },
1163→+  { note: 'A4', dur: 2 }, { note: 'G4', dur: 2 },
1164→+  { note: 'C4', dur: 1 }, { note: 'D4', dur: 1 }, { note: 'E4', dur: 1 }, { note: 'G4', dur: 1 },
1165→+  { note: 'A4', dur: 1 }, { note: 'G4', dur: 1 }, { note: 'E4', dur: 1 }, { note: 'D4', dur: 1 },
1166→+  { note: 'C4', dur: 1 }, { note: 'E4', dur: 1 }, { note: 'G4', dur: 1 }, { note: 'E4', dur: 1 },
1167→+  { note: 'D4', dur: 1 }, { note: 'C4', dur: 3 }
1168→+];
1169→+
1170→+const bassLine = [
1171→+  { note: 'C3', dur: 4 }, { note: 'A2', dur: 4 }, { note: 'C3', dur: 4 }, { note: 'A2', dur: 4 },
1172→+  { note: 'C3', dur: 4 }, { note: 'G2', dur: 4 }, { note: 'D3', dur: 4 }, { note: 'C3', dur: 4 }
1173→+];
