1179→+var masterGain = null;
1180→+
1181→+function initAudio() {
1182→+  if (audioCtx) return;
1183→+  try {
1184→+    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
1185→+    masterGain = audioCtx.createGain();
1186→+    masterGain.gain.value = 1.0;
1187→+    masterGain.connect(audioCtx.destination);
1188→+    musicInitialized = true;
1189→+  } catch (e) {
1190→+    console.warn('Web Audio not available:', e);
1191→+  }
