1193→+
1194→+function playNote(freq, startTime, duration, type, gainVal) {
1195→+  if (!audioCtx || freq === 0) return;
1196→+  const osc = audioCtx.createOscillator();
1197→+  const gain = audioCtx.createGain();
1198→+  osc.type = type;
1199→+  osc.frequency.setValueAtTime(freq, startTime);
1200→+  // Envelope: attack then decay
1201→+  gain.gain.setValueAtTime(0.001, startTime);
1202→+  gain.gain.linearRampToValueAtTime(gainVal, startTime + 0.02);
1203→+  gain.gain.setValueAtTime(gainVal, startTime + duration * 0.75);
1204→+  gain.gain.linearRampToValueAtTime(0.001, startTime + duration * 0.95);
1205→+  osc.connect(gain);
1206→+  gain.connect(masterGain || audioCtx.destination);
1207→+  osc.start(startTime);
1208→+  osc.stop(startTime + duration);
1209→+}
1210→+
1211→+function scheduleLoop() {
1212→+  if (!musicPlaying || !audioCtx) return;
1213→+  const bpm = 110;
1214→+  const quarterDur = 60 / bpm;
1215→+  const now = audioCtx.currentTime;
1216→+
1217→+  // Schedule melody
1218→+  let t = now + 0.05;
1219→+  for (const note of melody) {
1220→+    const dur = note.dur * quarterDur;
1221→+    if (note.note !== 'REST') {
1222→+      playNote(NOTE_FREQ[note.note], t, dur, 'square', 0.06);
1223→+    }
1224→+    t += dur;
1225→+  }
1226→+
1227→+  // Schedule bass
1228→+  let tb = now + 0.05;
1229→+  for (const note of bassLine) {
1230→+    const dur = note.dur * quarterDur;
1231→+    playNote(NOTE_FREQ[note.note], tb, dur, 'triangle', 0.08);
1232→+    tb += dur;
1233→+  }
1234→+
1235→+  // Total loop duration in beats: melody has 32 quarter beats = 32 * quarterDur
1236→+  const totalBeats = 32;
1237→+  const loopDurationMs = totalBeats * quarterDur * 1000;
1238→+
1239→+  musicScheduleTimer = setTimeout(scheduleLoop, loopDurationMs - 200);
1240→+}
1241→+
1242→+function startMusic() {
1243→+  if (!musicInitialized) initAudio();
1244→+  if (!audioCtx) return;
1245→+  if (audioCtx.state === 'suspended') audioCtx.resume();
1246→+  if (masterGain) masterGain.gain.setValueAtTime(1.0, audioCtx.currentTime);
1247→+  musicPlaying = true;
1248→+  scheduleLoop();
1249→+  updateMusicIndicator();
1250→+}
