1252→+function stopMusic() {
1253→+  musicPlaying = false;
1254→+  if (musicScheduleTimer) {
1255→+    clearTimeout(musicScheduleTimer);
1256→+    musicScheduleTimer = null;
1257→+  }
1258→+  if (masterGain) masterGain.gain.setValueAtTime(0, audioCtx.currentTime);
1259→+  updateMusicIndicator();
1260→+}
