1282→+const TS_KEYWORDS = new Set([
1283→+  'import', 'export', 'from', 'const', 'let', 'var', 'function', 'async',
1284→+  'await', 'return', 'if', 'else', 'for', 'while', 'new', 'typeof', 'instanceof',
1285→+  'interface', 'type', 'class', 'extends', 'implements', 'try', 'catch', 'throw',
1286→+  'default', 'switch', 'case', 'break', 'continue', 'true', 'false', 'null',
1287→+  'undefined', 'void', 'of', 'in'
