1290→+function escHtml(s) {
1291→+  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
1292→+}
1293→+
1294→+function highlightCode(code) {
1295→+  return code.split('\n').map(function(line) {
1296→+    if (line.trim().startsWith('//')) {
1297→+      return '<span style="color:#555555">' + escHtml(line) + '</span>';
1298→+    }
1299→+    var result = '';
1300→+    var i = 0;
1301→+    while (i < line.length) {
1302→+      // String literal
1303→+      if (line[i] === "'" || line[i] === '"' || line[i] === '`') {
1304→+        var quote = line[i];
1305→+        var end = i + 1;
1306→+        while (end < line.length && line[end] !== quote) {
1307→+          if (line[end] === '\\') end++;
1308→+          end++;
1309→+        }
1310→+        end = Math.min(end + 1, line.length);
1311→+        result += '<span style="color:#FFFF55">' + escHtml(line.substring(i, end)) + '</span>';
1312→+        i = end;
1313→+        continue;
1314→+      }
1315→+      // Inline comment
1316→+      if (line[i] === '/' && i + 1 < line.length && line[i + 1] === '/') {
1317→+        result += '<span style="color:#555555">' + escHtml(line.substring(i)) + '</span>';
1318→+        break;
1319→+      }
1320→+      // Number
1321→+      if (/\d/.test(line[i]) && (i === 0 || !/\w/.test(line[i - 1]))) {
1322→+        var end2 = i;
1323→+        while (end2 < line.length && /[\d._]/.test(line[end2])) end2++;
1324→+        result += '<span style="color:#FF55FF">' + escHtml(line.substring(i, end2)) + '</span>';
1325→+        i = end2;
1326→+        continue;
1327→+      }
1328→+      // Identifier or keyword
1329→+      if (/[a-zA-Z_$]/.test(line[i])) {
1330→+        var end3 = i;
1331→+        while (end3 < line.length && /[\w$]/.test(line[end3])) end3++;
1332→+        var word = line.substring(i, end3);
1333→+        if (TS_KEYWORDS.has(word)) {
1334→+          result += '<span style="color:#55FFFF">' + escHtml(word) + '</span>';
1335→+        } else {
1336→+          result += '<span style="color:#55FF55">' + escHtml(word) + '</span>';
1337→+        }
1338→+        i = end3;
1339→+        continue;
1340→+      }
1341→+      // Punctuation / operators
1342→+      result += '<span style="color:#AAAAAA">' + escHtml(line[i]) + '</span>';
1343→+      i++;
1344→+    }
1345→+    return result;
1346→+  }).join('\n');
1347→+}
